BEGIN; CREATE OR REPLACE FUNCTION public.can_view_reports() RETURNS boolean LANGUAGE sql SECURITY DEFINER SET search_path = public STABLE AS $$ SELECT public.is_admin() OR EXISTS (SELECT 1 FROM public.profiles p WHERE p.id = auth.uid() AND p.department = 'accounting' AND COALESCE(p.is_active, false) = true AND COALESCE(p.is_approved, false) = true AND p.deleted_at IS NULL); $$; REVOKE ALL ON FUNCTION public.can_view_reports() FROM PUBLIC, anon; GRANT EXECUTE ON FUNCTION public.can_view_reports() TO authenticated; DROP POLICY IF EXISTS "products_insert" ON public.products; CREATE POLICY "products_insert" ON public.products FOR INSERT TO authenticated WITH CHECK (public.is_approved_active_user()); DROP POLICY IF EXISTS "rc_select" ON public.inventory_report_closures; DROP POLICY IF EXISTS "rc_insert" ON public.inventory_report_closures; DROP POLICY IF EXISTS "rc_update" ON public.inventory_report_closures; CREATE POLICY "rc_select" ON public.inventory_report_closures FOR SELECT TO authenticated USING (public.can_view_reports() AND deleted_at IS NULL); CREATE POLICY "rc_insert" ON public.inventory_report_closures FOR INSERT TO authenticated WITH CHECK (public.can_view_reports()); CREATE POLICY "rc_update" ON public.inventory_report_closures FOR UPDATE TO authenticated USING (public.can_view_reports() AND deleted_at IS NULL) WITH CHECK (public.can_view_reports()); DROP POLICY IF EXISTS "rcl_select" ON public.inventory_report_closure_lines; DROP POLICY IF EXISTS "rcl_insert" ON public.inventory_report_closure_lines; DROP POLICY IF EXISTS "rcl_update" ON public.inventory_report_closure_lines; CREATE POLICY "rcl_select" ON public.inventory_report_closure_lines FOR SELECT TO authenticated USING (public.can_view_reports() AND deleted_at IS NULL); CREATE POLICY "rcl_insert" ON public.inventory_report_closure_lines FOR INSERT TO authenticated WITH CHECK (public.can_view_reports()); CREATE POLICY "rcl_update" ON public.inventory_report_closure_lines FOR UPDATE TO authenticated USING (public.can_view_reports() AND deleted_at IS NULL) WITH CHECK (public.can_view_reports()); DO $do$ BEGIN IF to_regprocedure('public.sales_command_center_report_v2_internal_20260718(date,date,date,date)') IS NULL THEN IF to_regprocedure('public.sales_command_center_report_v2(date,date,date,date)') IS NULL THEN RAISE EXCEPTION 'Khong tim thay sales_command_center_report_v2 de bao ve.'; END IF; ALTER FUNCTION public.sales_command_center_report_v2(date, date, date, date) RENAME TO sales_command_center_report_v2_internal_20260718; END IF; END $do$; REVOKE ALL ON FUNCTION public.sales_command_center_report_v2_internal_20260718(date, date, date, date) FROM PUBLIC, anon, authenticated; CREATE OR REPLACE FUNCTION public.sales_command_center_report_v2(p1_start date, p1_end date, p2_start date, p2_end date) RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path = public, pg_temp AS $$ BEGIN IF auth.uid() IS NULL OR NOT public.can_view_reports() THEN RAISE EXCEPTION 'Chi Ke toan hoac Admin duoc xem bao cao Sales.' USING ERRCODE = '42501'; END IF; RETURN public.sales_command_center_report_v2_internal_20260718(p1_start, p1_end, p2_start, p2_end); END; $$; REVOKE ALL ON FUNCTION public.sales_command_center_report_v2(date, date, date, date) FROM PUBLIC, anon, authenticated; GRANT EXECUTE ON FUNCTION public.sales_command_center_report_v2(date, date, date, date) TO authenticated; NOTIFY pgrst, 'reload schema'; COMMIT;
